data.index.css:
@import url("https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap");
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}
:root {
  --c0: #000000;
  --c1: #1c1c1e;
  --cyan: #0a84ff;
  --purple: #5e5ce6;
  --green: #30d158;
  --red: #ff453a;
  --orange: #ff9f0a;
  --yellow: #ffd60a;
  --t1: rgba(255, 255, 255, 0.96);
  --t2: rgba(235, 235, 245, 0.6);
  --t3: rgba(235, 235, 245, 0.3);
  --glass: rgba(28, 28, 30, 0.7);
  --border: rgba(255, 255, 255, 0.1);
  --mono: "JetBrains Mono", "Consolas", monospace;
  --sans:
    "Inter", -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica,
    Arial, sans-serif;
}
html,
body {
  height: 100%;
  overflow: hidden;
  background: var(--c0);
  color: var(--t1);
  font-family: var(--sans);
  -webkit-font-smoothing: antialiased;
}
#cv {
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  opacity: 0.5;
}

/* LAYOUT */
#shell {
  position: relative;
  z-index: 10;
  display: grid;
  grid-template-columns: 210px 1fr;
  grid-template-rows: 52px 1fr;
  height: 100vh;
  width: 100vw;
}

/* TOPBAR */
#top {
  grid-column: 1/-1;
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 0 18px;
  background: rgba(28, 28, 30, 0.65);
  border-bottom: 1px solid var(--border);
  backdrop-filter: saturate(180%) blur(20px);
  z-index: 20;
}
.logo {
  display: flex;
  align-items: center;
  gap: 9px;
}
.logo-icon {
  width: 30px;
  height: 30px;
  border-radius: 8px;
  background: var(--cyan);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 15px;
  box-shadow: 0 0 24px rgba(0, 212, 255, 0.45);
}
.logo-name {
  font-size: 13px;
  font-weight: 800;
  letter-spacing: 0.1em;
  background: linear-gradient(90deg, #fff, rgba(255, 255, 255, 0.65));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}
.logo-ver {
  font-size: 9px;
  background: rgba(0, 212, 255, 0.1);
  color: var(--cyan);
  padding: 2px 7px;
  border-radius: 4px;
  border: 1px solid rgba(0, 212, 255, 0.25);
  font-family: var(--mono);
}
.sep {
  flex: 1;
}
.top-stat {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 11px;
  font-weight: 700;
  font-family: var(--mono);
  letter-spacing: 0.07em;
}
.dot {
  display: inline-block;
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--green);
  box-shadow: 0 0 8px var(--green);
  animation: pg 2s ease-in-out infinite;
  flex-shrink: 0;
}
.dot.warn {
  background: var(--yellow);
  box-shadow: 0 0 8px var(--yellow);
}
.dot.err {
  background: var(--red);
  box-shadow: none;
  animation: none;
}
@keyframes pg {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.3;
  }
}
.top-clock {
  font-family: var(--mono);
  font-size: 11px;
  color: var(--t2);
  background: rgba(255, 255, 255, 0.05);
  padding: 4px 10px;
  border-radius: 5px;
  border: 1px solid var(--border);
}

/* SIDEBAR */
#side {
  background: rgba(24, 24, 26, 0.95);
  border-right: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  overflow-y: auto;
  padding: 10px 0;
}
.nsec {
  padding: 10px 14px 4px;
  font-size: 9px;
  font-weight: 700;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--t3);
}
.ni {
  display: flex;
  align-items: center;
  gap: 9px;
  padding: 8px 15px;
  font-size: 12px;
  font-weight: 500;
  color: var(--t2);
  cursor: pointer;
  border: none;
  background: none;
  width: 100%;
  text-align: left;
  transition: all 0.15s;
  border-left: 2px solid transparent;
  font-family: var(--sans);
}
.ni:hover {
  color: var(--t1);
  background: rgba(255, 255, 255, 0.04);
  border-left-color: rgba(255, 255, 255, 0.15);
}
.ni.on {
  color: var(--cyan);
  background: rgba(0, 212, 255, 0.07);
  border-left-color: var(--cyan);
}
.ni .ic {
  font-size: 14px;
  width: 18px;
  text-align: center;
}
.nb {
  margin-left: auto;
  font-size: 9px;
  font-family: var(--mono);
  font-weight: 700;
  padding: 2px 6px;
  border-radius: 3px;
  background: rgba(0, 212, 255, 0.12);
  color: var(--cyan);
  border: 1px solid rgba(0, 212, 255, 0.2);
}
.nb.g {
  background: rgba(16, 185, 129, 0.12);
  color: var(--green);
  border-color: rgba(16, 185, 129, 0.2);
}
.nb.o {
  background: rgba(249, 115, 22, 0.12);
  color: var(--orange);
  border-color: rgba(249, 115, 22, 0.2);
}
.sfooter {
  margin-top: auto;
  padding: 12px 14px;
  border-top: 1px solid var(--border);
  font-size: 10px;
  color: var(--t3);
  text-align: center;
  font-family: var(--mono);
}

/* MAIN */
#main {
  overflow-y: auto;
  overflow-x: hidden;
  display: flex;
  flex-direction: column;
  background: rgba(4, 6, 14, 0.4);
}
.view {
  display: none;
  flex-direction: column;
  gap: 14px;
  padding: 18px;
}
.view.on {
  display: flex;
  animation: fsu 0.25s ease;
}
.fullh {
  height: calc(100vh - 52px);
  padding: 16px;
  display: none;
  flex-direction: column;
  gap: 14px;
}
.fullh.on {
  display: flex;
  animation: fsu 0.25s ease;
}
@keyframes fsu {
  from {
    opacity: 0;
    transform: translateY(8px);
  }
  to {
    opacity: 1;
    transform: none;
  }
}

/* KPI CARDS */
.krow {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 12px;
}
.kcard {
  background: rgba(12, 18, 32, 0.9);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 15px 16px;
  position: relative;
  overflow: hidden;
  transition: all 0.2s;
}
.kcard:hover {
  border-color: rgba(0, 212, 255, 0.2);
  transform: translateY(-1px);
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.4);
}

.klbl {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--t3);
  margin-bottom: 6px;
}
.kval {
  font-size: 28px;
  font-weight: 700;
  font-family: var(--mono);
  line-height: 1;
  transition: all 0.3s;
}
.kval.c {
  color: var(--cyan);
}
.kval.p {
  color: #a78bfa;
}
.kval.g {
  color: var(--green);
}
.kval.o {
  color: var(--orange);
}
.ksub {
  font-size: 10px;
  color: var(--t3);
  margin-top: 4px;
  font-family: var(--mono);
}
.kbw {
  margin-top: 10px;
  background: rgba(255, 255, 255, 0.05);
  border-radius: 2px;
  height: 3px;
  overflow: hidden;
}
.kb {
  height: 100%;
  border-radius: 2px;
  transition: width 0.8s cubic-bezier(0.4, 0, 0.2, 1);
  width: 0%;
}
.kb.c {
  background: var(--cyan);
}
.kb.p {
  background: var(--purple);
}
.kb.g {
  background: var(--green);
}
.kb.o {
  background: var(--orange);
}

/* GRID LAYOUTS */
.g2 {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 14px;
  align-items: start;
}
.g3 {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 14px;
}
.g-auto {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(128px, 1fr));
  gap: 10px;
}

/* PANELS */
.panel {
  background: var(--glass);
  border: 1px solid var(--border);
  border-radius: 16px;
  overflow: hidden;
  backdrop-filter: saturate(180%) blur(20px);
  display: flex;
  flex-direction: column;
}
.ph {
  display: flex;
  align-items: center;
  gap: 9px;
  padding: 11px 16px;
  border-bottom: 1px solid var(--border);
  background: rgba(0, 0, 0, 0.15);
  flex-shrink: 0;
}
.pt {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--t2);
}
.pi {
  font-size: 13px;
}
.pbadge {
  margin-left: auto;
  font-size: 9px;
  font-family: var(--mono);
  color: var(--t3);
}
.pb {
  padding: 12px 14px;
  flex: 1;
  overflow: auto;
}

/* TABLE */
.stbl {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0 3px;
}
.stbl th {
  font-size: 9px;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--t3);
  padding: 3px 8px;
  text-align: left;
}
.srow {
  background: rgba(255, 255, 255, 0.025);
  border-radius: 6px;
  transition: background 0.15s;
}
.srow:hover {
  background: rgba(255, 255, 255, 0.05);
}
.srow td {
  padding: 8px;
  font-size: 12px;
  vertical-align: middle;
}

/* PILLS & TAGS */
.pill {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 2px 8px;
  border-radius: 20px;
  font-size: 10px;
  font-weight: 700;
  font-family: var(--mono);
}
.pill.u {
  background: rgba(16, 185, 129, 0.12);
  border: 1px solid rgba(16, 185, 129, 0.3);
  color: var(--green);
}
.pill.d {
  background: rgba(239, 68, 68, 0.12);
  border: 1px solid rgba(239, 68, 68, 0.3);
  color: var(--red);
}
.pill.w {
  background: rgba(234, 179, 8, 0.12);
  border: 1px solid rgba(234, 179, 8, 0.3);
  color: var(--yellow);
}
.pdot {
  width: 5px;
  height: 5px;
  border-radius: 50%;
  background: currentColor;
  display: inline-block;
}
.ptag {
  font-family: var(--mono);
  font-size: 10px;
  color: var(--t3);
  background: rgba(255, 255, 255, 0.05);
  padding: 2px 6px;
  border-radius: 4px;
}
.plat {
  font-family: var(--mono);
  font-size: 11px;
  color: var(--t2);
}
.tag {
  display: inline-block;
  font-size: 9px;
  font-weight: 700;
  padding: 2px 6px;
  border-radius: 3px;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  font-family: var(--mono);
}
.tc {
  background: rgba(0, 212, 255, 0.1);
  color: var(--cyan);
  border: 1px solid rgba(0, 212, 255, 0.2);
}
.tp {
  background: rgba(139, 92, 246, 0.12);
  color: #a78bfa;
  border: 1px solid rgba(139, 92, 246, 0.25);
}
.tg {
  background: rgba(16, 185, 129, 0.12);
  color: var(--green);
  border: 1px solid rgba(16, 185, 129, 0.25);
}
.to {
  background: rgba(249, 115, 22, 0.12);
  color: var(--orange);
  border: 1px solid rgba(249, 115, 22, 0.25);
}
.tr {
  background: rgba(239, 68, 68, 0.12);
  color: var(--red);
  border: 1px solid rgba(239, 68, 68, 0.25);
}

/* LOGS */
.sbox {
  background: rgba(1, 2, 6, 0.85);
  border: 1px solid var(--border);
  border-radius: 8px;
  font-family: var(--mono);
  font-size: 11px;
  line-height: 1.75;
  padding: 10px 12px;
  overflow-y: auto;
  max-height: 220px;
}
.ll {
  display: flex;
  gap: 7px;
  line-height: 1.5;
}
.ts {
  color: var(--t3);
  flex-shrink: 0;
  font-size: 10px;
}
.lt {
  color: var(--t2);
}
.lt.s {
  color: var(--green);
}
.lt.e {
  color: var(--red);
}
.lt.w {
  color: var(--yellow);
}
.lt.i {
  color: var(--cyan);
}
.lt.x {
  color: #a78bfa;
}

/* AGENTS */
.acard {
  background: rgba(12, 18, 32, 0.6);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 16px;
  padding: 16px 12px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  cursor: default;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  position: relative;
  text-align: center;
  backdrop-filter: blur(10px);
  overflow: hidden;
}
.acard::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 2px;
  background: linear-gradient(90deg, transparent, var(--cyan), transparent);
  opacity: 0;
  transition: opacity 0.3s;
}
.acard:hover {
  border-color: rgba(0, 212, 255, 0.4);
  background: rgba(0, 212, 255, 0.05);
  transform: translateY(-4px);
  box-shadow: 0 8px 30px rgba(0, 212, 255, 0.15);
}
.acard:hover::before {
  opacity: 1;
}
.adot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--green);
  box-shadow: 0 0 10px var(--green);
  animation: pg 2s ease-in-out infinite;
  position: absolute;
  top: 10px;
  right: 10px;
}
.ae {
  font-size: 28px;
  line-height: 1;
  filter: drop-shadow(0 2px 4px rgba(0, 0, 0, 0.5));
}
.an {
  font-size: 13px;
  font-weight: 700;
  color: var(--t1);
  letter-spacing: 0.05em;
}
.agent-group-title {
  grid-column: 1 / -1;
  font-size: 11px;
  font-family: var(--mono);
  font-weight: 700;
  color: var(--t3);
  text-transform: uppercase;
  letter-spacing: 0.15em;
  padding-bottom: 8px;
  margin-top: 10px;
  border-bottom: 1px dashed var(--border);
}

/* FORMS */
.dta {
  background: rgba(0, 0, 0, 0.5);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 8px;
  padding: 10px 12px;
  color: var(--t1);
  font-size: 13px;
  outline: none;
  resize: none;
  width: 100%;
  font-family: var(--sans);
  transition: border-color 0.2s;
}
.dta:focus {
  border-color: rgba(0, 212, 255, 0.4);
}
.ds {
  background: rgba(0, 0, 0, 0.4);
  border: 1px solid var(--border);
  color: var(--t2);
  padding: 7px 10px;
  border-radius: 6px;
  font-size: 11px;
  font-family: var(--sans);
  outline: none;
}
.btn {
  padding: 6px 16px;
  border-radius: 99px;
  font-size: 12px;
  font-weight: 600;
  border: none;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  gap: 5px;
  font-family: var(--sans);
  transition: all 0.2s;
}
.bp {
  background: var(--cyan);
  color: #000;
}
.bp:hover {
  box-shadow: 0 4px 18px rgba(0, 212, 255, 0.35);
  filter: brightness(1.1);
}
.bg {
  background: rgba(255, 255, 255, 0.07);
  color: var(--t2);
  border: 1px solid var(--border);
}
.bg:hover {
  background: rgba(255, 255, 255, 0.12);
  color: var(--t1);
}
.bc {
  background: rgba(0, 212, 255, 0.12);
  color: var(--cyan);
  border: 1px solid rgba(0, 212, 255, 0.25);
  text-decoration: none;
}
.bc:hover {
  background: rgba(0, 212, 255, 0.2);
}

/* SPARKLINES */
.spkw {
  display: flex;
  align-items: flex-end;
  gap: 2px;
  height: 28px;
  margin-top: 8px;
}
.spk {
  flex: 1;
  border-radius: 2px 2px 0 0;
  min-width: 3px;
  transition: height 0.4s ease;
}

/* INFRA METRIC CARDS */
.metric-big {
  text-align: center;
  padding: 16px 16px 8px;
}
.metric-val-big {
  font-size: 38px;
  font-weight: 800;
  font-family: var(--mono);
  line-height: 1;
  transition: all 0.4s;
}
.metric-lbl-big {
  font-size: 9px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--t3);
  margin-top: 6px;
}
.metric-bar-big {
  margin: 12px auto 0;
  max-width: 100%;
  height: 4px;
  background: rgba(255, 255, 255, 0.06);
  border-radius: 2px;
  overflow: hidden;
}
.metric-bar-fill {
  height: 100%;
  border-radius: 2px;
  transition: width 0.8s ease;
}

/* N8N VIEW */
.n8n-hero {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 14px 18px;
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}
.n8n-title {
  font-size: 14px;
  font-weight: 700;
  display: flex;
  align-items: center;
  gap: 8px;
}
.n8n-actions {
  margin-left: auto;
  display: flex;
  gap: 8px;
  align-items: center;
}
.n8n-stat-row {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}
.n8n-stat {
  text-align: center;
  padding: 14px 10px;
  border-right: 1px solid var(--border);
}
.n8n-stat:last-child {
  border-right: none;
}
.n8n-stat-val {
  font-size: 24px;
  font-weight: 700;
  font-family: var(--mono);
}
.n8n-stat-lbl {
  font-size: 9px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--t3);
  margin-top: 3px;
}
.wflow-list {
  overflow-y: auto;
  flex: 1;
}
.wflow-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px 16px;
  border-bottom: 1px solid var(--border);
  transition: background 0.15s;
  cursor: default;
}
.wflow-item:hover {
  background: rgba(255, 255, 255, 0.03);
}
.wflow-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
}
.wflow-dot.on {
  background: var(--green);
  box-shadow: 0 0 8px var(--green);
  animation: pg 2s infinite;
}
.wflow-dot.off {
  background: var(--t3);
}
.wflow-name {
  font-size: 13px;
  font-weight: 500;
}
.wflow-meta {
  font-size: 10px;
  color: var(--t3);
  margin-top: 2px;
  font-family: var(--mono);
}
.wflow-empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 120px;
  color: var(--t3);
  font-size: 12px;
  gap: 8px;
}
.exec-item {
  padding: 10px 14px;
  border-bottom: 1px solid var(--border);
  font-size: 11px;
  font-family: var(--mono);
}
.exec-item:hover {
  background: rgba(255, 255, 255, 0.03);
}
.exec-status {
  font-size: 9px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  margin-top: 2px;
}
.auth-notice {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 40px;
  gap: 12px;
  color: var(--t2);
  text-align: center;
}
.auth-notice h3 {
  color: var(--t1);
  margin-bottom: 6px;
}
.auth-notice code {
  font-family: var(--mono);
  background: rgba(0, 212, 255, 0.1);
  color: var(--cyan);
  padding: 4px 10px;
  border-radius: 4px;
  font-size: 12px;
}


/* CHAT BUBBLES */
.chat-bubble {
  max-width: 85%;
  padding: 8px 14px;
  border-radius: 18px;
  font-size: 13px;
  line-height: 1.5;
  margin-bottom: 4px;
  backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.08);
  word-wrap: break-word;
  animation: fadeIn 0.3s ease;
}
.chat-bubble.bg {
  background: rgba(10, 132, 255, 0.2);
  border-color: rgba(10, 132, 255, 0.3);
  color: #fff;
  align-self: flex-end;
  border-bottom-right-radius: 4px;
}
.chat-bubble.bp {
  background: rgba(255, 255, 255, 0.05);
  color: var(--t1);
  align-self: flex-start;
  border-bottom-left-radius: 4px;
}
@keyframes fadeIn {
