"""
RealMaestroAgent - The Orchestrator Brain

This is the central intelligence that:
1. Analyzes incoming tickets/tasks
2. Decides which agents to dispatch
3. Coordinates multi-agent workflows
4. Synthesizes results into actionable solutions

Supports both LLM-based decisions (Ollama/Claude) and rule-based fallback.
"""

from __future__ import annotations

import logging
import os
from dataclasses import dataclass, field
from datetime import datetime, timezone
from enum import Enum
from typing import Any, Dict, List, Optional

try:
    import httpx
except ImportError:
    httpx = None

from twisterlab.agents.core.base import (
    CoreAgent,
    AgentCapability,
    AgentResponse,
    CapabilityType,
    CapabilityParam,
    ParamType,
)

logger = logging.getLogger(__name__)


class TaskPriority(Enum):
    CRITICAL = "critical"
    HIGH = "high"
    MEDIUM = "medium"
    LOW = "low"


class TaskCategory(Enum):
    DATABASE = "database"
    NETWORK = "network"
    APPLICATION = "application"
    SECURITY = "security"
    INFRASTRUCTURE = "infrastructure"
    MONITORING = "monitoring"
    UNKNOWN = "unknown"


@dataclass
class OrchestratedTask:
    id: str
    description: str
    priority: TaskPriority = TaskPriority.MEDIUM
    category: TaskCategory = TaskCategory.UNKNOWN
    agents_involved: List[str] = field(default_factory=list)
    steps: List[Dict[str, Any]] = field(default_factory=list)
    results: List[Dict[str, Any]] = field(default_factory=list)
    status: str = "pending"
    created_at: str = field(default_factory=lambda: datetime.now(timezone.utc).isoformat())
    completed_at: Optional[str] = None



class _ToolRouterAgentProxy:
    """Proxy that allows calling agent.execute(capability, **params) via ToolRouter."""
    def __init__(self, agent_name: str, tool_router):
        self.name = agent_name
        self._router = tool_router

    async def execute(self, capability: str, **kwargs):
        import json
        # Normalize agent name (e.g. sentiment-analyzer -> sentiment_analyzer)
        prefix = self.name.replace("-", "_")
        tool_name = f"{prefix}_{capability}"
        result = await self._router.execute_tool(tool_name, kwargs)
        if result.get("isError"):
            err = result.get("content", [{}])[0].get("text", "error")
            from twisterlab.agents.core.base import AgentResponse
            return AgentResponse(success=False, error=err)
        text = result.get("content", [{}])[0].get("text", "{}")
        try:
            data = json.loads(text)
        except Exception:
            data = {"raw": text}
        from twisterlab.agents.core.base import AgentResponse
        return AgentResponse(success=True, data=data)


class RealMaestroAgent(CoreAgent):
    """The Maestro Orchestrator - Central brain for multi-agent coordination."""

    def __init__(self, registry=None, agent_registry=None) -> None:
        super().__init__(registry)
        self._agent_registry = agent_registry
        self._ollama_url = os.getenv("OLLAMA_BASE_URL", "http://localhost:11434")
        self._ollama_model = os.getenv("OLLAMA_MODEL", "llama3.2")
        self._use_llm = os.getenv("MAESTRO_USE_LLM", "true").lower() == "true"
        self.status_callback = None  # UI progress callback

    @property
    def name(self) -> str:
        return "maestro"

    @property
    def description(self) -> str:
        return "Orchestrates multi-agent workflows intelligently"

    @property
    def agent_registry(self):
        if self._agent_registry is None:
            try:
                from twisterlab.agents.mcp.router import AgentRegistry as MCPRegistry
                self._agent_registry = MCPRegistry()
            except Exception:
                logger.warning("Could not import MCPRegistry")
        return self._agent_registry

    @agent_registry.setter
    def agent_registry(self, value):
        self._agent_registry = value

    def get_capabilities(self) -> List[AgentCapability]:
        return [
            AgentCapability(
                name="orchestrate",
                description="Orchestrate a complete task workflow across multiple agents",
                handler="handle_orchestrate",
                capability_type=CapabilityType.ACTION,
                params=[
                    CapabilityParam("task", ParamType.STRING, "The task or ticket to process", required=True),
                    CapabilityParam("context", ParamType.OBJECT, "Additional context", required=False),
                    CapabilityParam("dry_run", ParamType.BOOLEAN, "Plan only, don't execute", required=False, default=False),
                ],
            ),
            AgentCapability(
                name="analyze_task",
                description="Analyze a task to determine category and priority",
                handler="handle_analyze_task",
                capability_type=CapabilityType.QUERY,
                params=[
                    CapabilityParam("task", ParamType.STRING, "The task description", required=True),
                ],
            ),
        ]

    async def handle_orchestrate(self, task: str, context: Optional[Dict[str, Any]] = None, dry_run: bool = False) -> AgentResponse:
        logger.info(f"Maestro dispatching mission: {task[:60]}...")

        # 1. ANALYZE TASK
        analysis = await self._analyze_task(task, context)

        # 2. PLAN
        plan_data = await self._create_plan(task, analysis, context)

        mission_id = f"M-{datetime.now().strftime('%Y%m%d')}-{str(abs(hash(task)) % 1000).zfill(3)}"

        orchestrated = OrchestratedTask(
            id=mission_id,
            description=task,
            priority=analysis["priority"],
            category=analysis["category"],
            agents_involved=plan_data["agents"],
            steps=plan_data["steps"]
        )

        # 3. DRY RUN (Simulation)
        if dry_run:
            return AgentResponse(success=True, data={
                "mission_id": orchestrated.id,
                "task": orchestrated.description,
                "plan": {
                    "steps": orchestrated.steps,
                    "estimated_duration": f"{len(orchestrated.steps) * 2}m",
                    "resources": {"cpu": "low" if len(orchestrated.steps) < 3 else "medium", "ram": "512MB"}
                },
                "status": "dry_run_complete"
            })

        # 4. DISPATCH
        if self.status_callback:
            self.status_callback({"type": "overall", "status": "dispatching", "mission_id": orchestrated.id})

        results = await self._execute_plan(plan_data, task, context)
        orchestrated.results = results
        orchestrated.status = "completed"
        orchestrated.completed_at = datetime.now(timezone.utc).isoformat()

        synthesis = await self._synthesize_results(task, results, analysis)
        synthesis["mission_id"] = orchestrated.id

        return AgentResponse(success=True, data=synthesis)

    async def handle_analyze_task(self, task: str) -> AgentResponse:
        analysis = await self._analyze_task(task, None)
        return AgentResponse(success=True, data={
            "mission_id": f"A-{datetime.now().strftime('%Y%m%d')}",
            "analysis": {
                "category": analysis["category"].value,
                "priority": analysis["priority"].value,
            },
            "suggested_agents": analysis["suggested_agents"],
            "plan_preview": f"Mission requires {len(analysis['suggested_agents'])} specialized agents."
        })

    async def _analyze_task(self, task: str, context: Optional[Dict[str, Any]]) -> Dict[str, Any]:
        if self._use_llm and httpx:
            llm_analysis = await self._llm_analyze(task, context)
            if llm_analysis:
                return llm_analysis
        return self._rule_based_analyze(task, context)

    async def _llm_analyze(self, task: str, context: Optional[Dict[str, Any]]) -> Optional[Dict[str, Any]]:
        try:
            prompt = f"""Tu es le Maestro Orchestrator v3.5.0. 
Analyse cette requ??te et r??ponds en JSON uniquement :
REQU??TE: {task}
FORMAT: {{"category": "database|network|application|security|infrastructure|monitoring|unknown", "priority": "critical|high|medium|low", "suggested_agents": [], "keywords": []}}"""

            async with httpx.AsyncClient(timeout=30.0) as client:
                response = await client.post(
                    f"{self._ollama_url}/api/generate",
                    json={"model": self._ollama_model, "prompt": prompt, "stream": False, "format": "json"}
                )
                if response.status_code == 200:
                    import json
                    result = response.json()
                    analysis = json.loads(result.get("response", "{}"))
                    return {
                        "category": TaskCategory(analysis.get("category", "unknown")),
                        "priority": TaskPriority(analysis.get("priority", "medium")),
                        "suggested_agents": analysis.get("suggested_agents", []),
                        "keywords": analysis.get("keywords", []),
                        "source": "llm",
                    }
        except Exception as e:
            logger.warning(f"LLM analysis failed: {e}")
        return None

    def _rule_based_analyze(self, task: str, context: Optional[Dict[str, Any]]) -> Dict[str, Any]:
        task_lower = task.lower()
        category = TaskCategory.UNKNOWN
        keywords = []
        suggested_agents = ["classifier"]

        if any(kw in task_lower for kw in ["database", "sql", "db"]):
            category = TaskCategory.DATABASE
            suggested_agents.extend(["database", "backup"])
        elif any(kw in task_lower for kw in ["cpu", "memory", "ram", "disk", "monitoring"]):
            category = TaskCategory.MONITORING
            suggested_agents.extend(["monitoring", "real-desktop-commander"])
        elif any(kw in task_lower for kw in ["security", "hack", "breach"]):
            category = TaskCategory.SECURITY
            suggested_agents.extend(["backup", "code-review"])
        elif any(kw in task_lower for kw in ["server", "k8s", "pod", "deploy"]):
            category = TaskCategory.INFRASTRUCTURE
            suggested_agents.extend(["monitoring", "real-desktop-commander"])

        priority = TaskPriority.MEDIUM
        if any(kw in task_lower for kw in ["urgent", "critical", "outage"]):
            priority = TaskPriority.CRITICAL
        elif any(kw in task_lower for kw in ["production", "asap", "important"]):
            priority = TaskPriority.HIGH

        return {"category": category, "priority": priority, "suggested_agents": list(set(suggested_agents)), "keywords": keywords, "source": "rules"}

    async def _create_plan(self, task: str, analysis: Dict[str, Any], context: Optional[Dict[str, Any]]) -> Dict[str, Any]:
        category = analysis["category"]
        mission_ts = datetime.now(timezone.utc).strftime("%Y%m%d%H%M")
        # Basic workflow steps
        steps = [
            {"order": 1, "agent": "classifier", "capability": "classify_ticket", "params": {"ticket_text": task}, "purpose": "Mission Classification"},
        ]

        if category == TaskCategory.DATABASE:
            steps.append({"order": 2, "agent": "database", "capability": "db_health", "params": {}, "purpose": "Check DB Cluster Status"})
            steps.append({"order": 3, "agent": "backup", "capability": "create_backup", "params": {"service_name": "db_prod"}, "purpose": "Safety Snapshot"})
        elif category == TaskCategory.INFRASTRUCTURE or any(kw in task.lower() for kw in ["knowledge", "base", "doc", "wiki"]):
            steps.append({"order": 2, "agent": "notion", "capability": "create_page", "params": {
                "title": f"Knowledge Base : {task[:30]}",
                "content": f"# Knowledge Base TwisterLab\n\n## 📋 Sujet\n{task}\n\n## 🛡??? ??tat du Syst??me\n- Cluster: Active\n- Core API: Version 3.5.9\n- Notion Sync: Ready",
                "tags": ["knowledge-base", "internal"]
            }, "purpose": "Document Knowledge Base"})

        steps.append({"order": len(steps) + 1, "agent": "resolver", "capability": "resolve_ticket", "params": {"ticket_id": "TKT-AUTO", "resolution_note": f"Orchestrated by Maestro v3.5"}, "purpose": "Final Resolution"})

        # Documentation step ??? toujours en dernier via NotionAgent
        steps.append({
            "order": len(steps) + 1,
            "agent": "notion",
            "capability": "log_mission",
            "params": {
                "mission_id": f"M-{mission_ts}",
                "task": task,
                "status": "completed",
                "agents_used": list(set(s["agent"] for s in steps)),
            },
            "purpose": "Documentation Notion de la mission",
        })

        return {"agents": list(set(s["agent"] for s in steps)), "steps": steps}

    async def _execute_plan(self, plan: Dict[str, Any], task: str, context: Optional[Dict[str, Any]]) -> List[Dict[str, Any]]:
        results = []
        for step in plan["steps"]:
            step_result = {"step": step["order"], "agent": step["agent"], "capability": step["capability"], "status": "pending"}
            try:
                agent = self._get_agent(step["agent"])
                if not agent:
                    step_result["status"] = "skipped"
                else:
                    result = await agent.execute(step["capability"], **step["params"])
                    step_result["status"] = "success" if result.success else "failed"
                    step_result["data"] = result.data
                    if result.error:
                        step_result["error"] = result.error
            except Exception as e:
                step_result["status"] = "error"
                step_result["error"] = str(e)

            if self.status_callback:
                self.status_callback({"type": "step", "order": step["order"], "agent": step["agent"], "status": step_result["status"]})
            results.append(step_result)
        return results

    def _inject_tool_router(self, tool_router) -> None:
        self._tool_router_live = tool_router

    def _get_agent(self, agent_name: str):
        router = getattr(self, '_tool_router_live', None)
        if router:
            prefix = agent_name.replace("-", "_")
            if any(t["name"].startswith(prefix + "_") for t in router.list_tools()):
                return _ToolRouterAgentProxy(agent_name, router)
        if self.agent_registry:
            return self.agent_registry.get_agent(agent_name)
        return None

    async def _synthesize_results(self, task: str, results: List[Dict[str, Any]], analysis: Dict[str, Any]) -> Dict[str, Any]:
        success_count = sum(1 for r in results if r["status"] == "success")
        findings = [f"{r['agent']}: {r['status']}" for r in results if r["status"] != "success"]
        agents_used = list(set(r["agent"] for r in results))

        # Mise ?? jour du log Notion avec les findings r??els (si disponible)
        notion_step = next((r for r in results if r.get("agent") == "notion"), None)
        if not notion_step or notion_step.get("status") != "success":
            try:
                notion_agent = self._get_agent("notion")
                if notion_agent:
                    mission_id = f"M-{datetime.now(timezone.utc).strftime('%Y%m%d%H%M')}"
                    await notion_agent.execute(
                        "log_mission",
                        mission_id=mission_id,
                        task=task,
                        status="completed" if success_count == len(results) else "partial",
                        findings=findings,
                        resolution=f"{success_count}/{len(results)} ??tapes r??ussies.",
                        agents_used=agents_used,
                    )
                    logger.info(f"📝 [maestro] Mission document??e dans Notion ({mission_id})")
            except Exception as e:
                logger.warning(f"?????? [maestro] Notion logging failed (non-bloquant): {e}")

        return {
            "status": "completed" if success_count == len(results) else "partial_success",
            "task": task,
            "plan": {
                "steps": [r["capability"] for r in results],
                "estimated_duration": f"{len(results)*2}m",
                "resources": {"cpu": "medium", "ram": "1GB"}
            },
            "findings": findings,
            "agents_used": agents_used,
            "synthesis": f"Mission termin??e avec {success_count}/{len(results)} ??tapes valid??es.",
            "requires_human": success_count < len(results),
            "notion_logged": bool(notion_step and notion_step.get("status") == "success"),
        }

__all__ = ["RealMaestroAgent", "TaskPriority", "TaskCategory", "OrchestratedTask"]

data.real_notion_agent.py:
"""
RealNotionAgent — Notion API Integration

Capabilities:
- create_page      : Create a new page in a Notion database or as child of another page
- search_pages     : Search across Notion workspace
- update_page      : Append content blocks to an existing page
- log_mission      : Structured mission log (dedicated shortcut for Maestro)
- get_page         : Retrieve a page by ID

Requires env var: NOTION_TOKEN (Bearer token from Notion integration)
                  NOTION_DEFAULT_DATABASE_ID (optional, parent DB for new pages)
"""

from __future__ import annotations

import logging
import os
from datetime import datetime, timezone
from typing import Any, Dict, List, Optional

try:
    import httpx
except ImportError:
    httpx = None

from twisterlab.agents.core.base import (
    TwisterAgent,
    AgentCapability,
    AgentResponse,
    CapabilityType,
    CapabilityParam,
    ParamType,
)

logger = logging.getLogger(__name__)

NOTION_API_BASE = "https://api.notion.com/v1"
NOTION_VERSION = "2022-06-28"


class RealNotionAgent(TwisterAgent):
    """
    Agent d'intégration Notion pour TwisterLab.

    Permet de créer, rechercher et mettre à jour des pages Notion.
    Utilisé par Maestro pour documenter automatiquement chaque mission résolue.
    """

    def __init__(self, registry=None) -> None:
        super().__init__(registry)
        self._token = os.getenv("NOTION_TOKEN", "")
        self._default_db_id = os.getenv("NOTION_DEFAULT_DATABASE_ID", "")

    @property
    def name(self) -> str:
        return "notion"

    @property
    def description(self) -> str:
        return "Gère les pages Notion pour la documentation des missions et la knowledge base"

    @property
    def version(self) -> str:
        return "1.0.0"

    def get_capabilities(self) -> List[AgentCapability]:
        return [
            AgentCapability(
                name="create_page",
                description="Crée une nouvelle page Notion dans une base de données ou en tant qu'enfant d'une page",
                handler="handle_create_page",
                capability_type=CapabilityType.ACTION,
                params=[
                    CapabilityParam("title", ParamType.STRING, "Titre de la page", required=True),
                    CapabilityParam("content", ParamType.STRING, "Contenu Markdown de la page", required=True),
                    CapabilityParam("parent_id", ParamType.STRING, "ID de la page/DB parente (utilise NOTION_DEFAULT_DATABASE_ID si vide)", required=False),
                    CapabilityParam("tags", ParamType.ARRAY, "Tags/catégories à appliquer", required=False),
                ],
            ),
            AgentCapability(
                name="search_pages",
                description="Recherche dans l'espace Notion par mot-clé",
                handler="handle_search",
                capability_type=CapabilityType.QUERY,
                params=[
                    CapabilityParam("query", ParamType.STRING, "Texte de recherche", required=True),
                    CapabilityParam("limit", ParamType.INTEGER, "Nombre max de résultats (défaut: 10)", required=False),
                ],
            ),
            AgentCapability(
                name="update_page",
                description="Ajoute des blocs de contenu à une page Notion existante",
                handler="handle_update_page",
                capability_type=CapabilityType.ACTION,
                params=[
                    CapabilityParam("page_id", ParamType.STRING, "ID de la page à mettre à jour", required=True),
                    CapabilityParam("content", ParamType.STRING, "Contenu Markdown à ajouter", required=True),
                ],
            ),
            AgentCapability(
                name="log_mission",
                description="Crée une page de log structuré pour une mission Maestro (shortcut)",
                handler="handle_log_mission",
                capability_type=CapabilityType.ACTION,
                params=[
                    CapabilityParam("mission_id", ParamType.STRING, "ID de la mission (ex: M-20260415-042)", required=True),
                    CapabilityParam("task", ParamType.STRING, "Description de la tâche originale", required=True),
                    CapabilityParam("status", ParamType.STRING, "Statut final de la mission", required=False),
                    CapabilityParam("findings", ParamType.ARRAY, "Résultats / findings clés", required=False),
                    CapabilityParam("resolution", ParamType.STRING, "Résumé de la résolution", required=False),
                    CapabilityParam("agents_used", ParamType.ARRAY, "Liste des agents utilisés", required=False),
                ],
            ),
            AgentCapability(
                name="get_page",
                description="Récupère les métadonnées d'une page Notion par son ID",
                handler="handle_get_page",
                capability_type=CapabilityType.QUERY,
                params=[
                    CapabilityParam("page_id", ParamType.STRING, "ID de la page Notion", required=True),
                ],
            ),
            AgentCapability(
                name="list_pages",
                description="Récupère une liste complète des pages (Search + Enfants directs)",
                handler="handle_list_pages",
                capability_type=CapabilityType.QUERY,
                params=[
                    CapabilityParam("limit", ParamType.INTEGER, "Limite de résultats", required=False),
                ],
            ),
        ]

    # -------------------------------------------------------------------------
    # HANDLERS
    # -------------------------------------------------------------------------

    async def handle_create_page(
        self,
        title: str,
        content: str,
        parent_id: Optional[str] = None,
        tags: Optional[List[str]] = None,
    ) -> AgentResponse:
        """Crée une page Notion avec titre et contenu Markdown."""
        if not self._token:
            return AgentResponse(
                success=False,
                error="NOTION_TOKEN non configuré. Ajoutez-le dans le fichier .env."
            )

        parent = parent_id or self._default_db_id
        if not parent:
            return AgentResponse(
                success=False,
                error="Aucun parent_id fourni et NOTION_DEFAULT_DATABASE_ID non configuré."
            )

        # Déterminer si le parent est une DB ou une Page
        # Par défaut on considère que c'est une Page si non spécifié
        parent_type = os.getenv("NOTION_PARENT_TYPE", "page").lower()
        is_db = (parent_type == "database") if not parent_id else False

        try:
            blocks = self._markdown_to_blocks(content)
            payload = self._build_page_payload(title, parent, blocks, is_database=is_db)

            response = await self._notion_request("POST", "/pages", payload)

            page_id = response.get("id", "")
            page_url = response.get("url", "")
            logger.info(f"✅ [notion] Page créée : {title} ({page_id})")

            return AgentResponse(
                success=True,
                data={
                    "page_id": page_id,
                    "title": title,
                    "url": page_url,
                    "blocks_created": len(blocks),
                    "parent_id": parent,
                },
            )

        except Exception as e:
            logger.error(f"❌ [notion] create_page failed: {e}")
            return AgentResponse(success=False, error=str(e))

    async def handle_search(
        self,
        query: str,
        limit: int = 10,
    ) -> AgentResponse:
        """Recherche des pages Notion par mot-clé."""
        if not self._token:
            return AgentResponse(success=False, error="NOTION_TOKEN non configuré.")

        try:
            payload = {
                "query": query,
                "page_size": min(limit, 100),
                "filter": {"value": "page", "property": "object"},
            }
            response = await self._notion_request("POST", "/search", payload)

            results = []
            for item in response.get("results", []):
                props = item.get("properties", {})
                # Extraire le titre selon le type de propriété
                title = self._extract_title(item)
                results.append({
                    "id": item.get("id"),
                    "title": title,
                    "url": item.get("url"),
                    "created_time": item.get("created_time"),
                    "last_edited_time": item.get("last_edited_time"),
                })

            logger.info(f"✅ [notion] Recherche '{query}' → {len(results)} résultats")
            return AgentResponse(
                success=True,
                data={"results": results, "count": len(results), "query": query},
            )

        except Exception as e:
            logger.error(f"❌ [notion] search failed: {e}")
            return AgentResponse(success=False, error=str(e))

    async def handle_update_page(self, page_id: str, content: str) -> AgentResponse:
        """Ajoute des blocs à une page Notion existante."""
        if not self._token:
            return AgentResponse(success=False, error="NOTION_TOKEN non configuré.")

        try:
            blocks = self._markdown_to_blocks(content)
            payload = {"children": blocks}

            await self._notion_request("PATCH", f"/blocks/{page_id}/children", payload)

            logger.info(f"✅ [notion] Page {page_id} mise à jour ({len(blocks)} blocs)")
            return AgentResponse(
                success=True,
                data={"page_id": page_id, "blocks_added": len(blocks)},
            )

        except Exception as e:
            logger.error(f"❌ [notion] update_page failed: {e}")
            return AgentResponse(success=False, error=str(e))

    async def handle_log_mission(
        self,
        mission_id: str,
        task: str,
        status: str = "completed",
        findings: Optional[List[str]] = None,
        resolution: Optional[str] = None,
        agents_used: Optional[List[str]] = None,
    ) -> AgentResponse:
        """Crée une page de rapport structuré pour une mission Maestro."""
        now = datetime.now(timezone.utc).strftime("%Y-%m-%d %H:%M UTC")

        content_lines = [
            f"## 🎯 Mission : {mission_id}",
            f"",
            f"**Date** : {now}",
            f"**Statut** : {'✅ ' if status == 'completed' else '⚠️ '}{status.upper()}",
            f"",
            f"## 📋 Tâche Originale",
            f"{task}",
            f"",
        ]

        if agents_used:
            content_lines += [
                f"## 🤖 Agents Utilisés",
                *[f"- {a}" for a in agents_used],
                f"",
            ]

        if findings:
            content_lines += [
                f"## 🔍 Findings",
                *[f"- {f}" for f in findings],
                f"",
            ]

        if resolution:
            content_lines += [
                f"## ✅ Résolution",
                f"{resolution}",
                f"",
            ]

        content_lines += [
            f"---",
            f"*Généré automatiquement par TwisterLab Maestro v3.5*",
        ]

        content = "\n".join(content_lines)
        title = f"[{mission_id}] {task[:60]}{'...' if len(task) > 60 else ''}"

        return await self.handle_create_page(
            title=title,
            content=content,
            tags=["mission", "auto-generated", status],
        )

    async def handle_get_page(self, page_id: str) -> AgentResponse:
        """Récupère les métadonnées d'une page."""
        if not self._token:
            return AgentResponse(success=False, error="NOTION_TOKEN non configuré.")

        try:
            response = await self._notion_request("GET", f"/pages/{page_id}", None)
            title = self._extract_title(response)

            return AgentResponse(
                success=True,
                data={
                    "page_id": response.get("id"),
                    "title": title,
                    "url": response.get("url"),
                    "created_time": response.get("created_time"),
                    "last_edited_time": response.get("last_edited_time"),
                    "archived": response.get("archived", False),
                },
            )

        except Exception as e:
            logger.error(f"❌ [notion] get_page failed: {e}")
            return AgentResponse(success=False, error=str(e))

    async def handle_list_pages(self, limit: int = 20) -> AgentResponse:
        """Combine Search et Fetch Children pour une synchro parfaite."""
        if not self._token:
            return AgentResponse(success=False, error="NOTION_TOKEN non configuré.")

        all_pages = {}

        try:
            # 1. Recherche globale (pour attraper tout ce qui est accessible)
            search_res = await self.handle_search(query="", limit=limit)
            if search_res.success:
                for p in search_res.data.get("results", []):
                    all_pages[p["id"]] = p

            # 2. Fetch direct des enfants du parent par défaut (si c'est une page)
            if self._default_db_id:
                try:
                    # On utilise l'API blocks children car les sous-pages sont des blocs
                    response = await self._notion_request("GET", f"/blocks/{self._default_db_id}/children", None)
                    for block in response.get("results", []):
                        if block["type"] == "child_page":
                            pid = block["id"]
                            if pid not in all_pages:
                                all_pages[pid] = {
                                    "id": pid,
                                    "title": block["child_page"]["title"],
                                    "url": f"https://www.notion.so/{pid.replace('-', '')}",
                                    "created_time": block["created_time"],
                                    "last_edited_time": block["last_edited_time"],
                                    "type": "page",
                                }
                except Exception as ex:
                    logger.warning(f"⚠️ [notion] Fallback children fetch failed: {ex}")

            # Trier par date de modif décroissante
            sorted_pages = sorted(all_pages.values(), key=lambda x: x.get("last_edited_time", ""), reverse=True)

            return AgentResponse(
                success=True,
                data={"pages": sorted_pages[:limit], "count": len(sorted_pages)}
            )

        except Exception as e:
            logger.error(f"❌ [notion] list_pages failed: {e}")
            return AgentResponse(success=False, error=str(e))

    # -------------------------------------------------------------------------
    # HELPERS PRIVÉS
    # -------------------------------------------------------------------------

    async def _notion_request(
        self,
        method: str,
        path: str,
        payload: Optional[Dict[str, Any]],
    ) -> Dict[str, Any]:
        """Exécute une requête vers l'API Notion."""
        if not httpx:
            raise RuntimeError("httpx non disponible. Installez-le : pip install httpx")

        headers = {
            "Authorization": f"Bearer {self._token}",
            "Notion-Version": NOTION_VERSION,
            "Content-Type": "application/json",
        }

        async with httpx.AsyncClient(timeout=30.0) as client:
            if method == "GET":
                response = await client.get(f"{NOTION_API_BASE}{path}", headers=headers)
            elif method == "POST":
                response = await client.post(f"{NOTION_API_BASE}{path}", headers=headers, json=payload)
            elif method == "PATCH":
                response = await client.patch(f"{NOTION_API_BASE}{path}", headers=headers, json=payload)
            else:
                raise ValueError(f"Méthode HTTP non supportée : {method}")

            if response.status_code >= 400:
                error_data = response.json()
                raise RuntimeError(
                    f"Notion API Error {response.status_code}: "
                    f"{error_data.get('message', response.text)}"
                )

            return response.json()

    def _markdown_to_blocks(self, markdown: str) -> List[Dict[str, Any]]:
        """Convertit du Markdown en blocs Notion (h1/h2/h3, bullets, paragraphes)."""
        blocks = []
        lines = markdown.split("\n")

        for line in lines:
            stripped = line.strip()
            if not stripped:
                # Bloc vide — séparateur
                continue

            if stripped.startswith("### "):
                blocks.append(self._heading_block(stripped[4:], level=3))
            elif stripped.startswith("## "):
                blocks.append(self._heading_block(stripped[3:], level=2))
            elif stripped.startswith("# "):
                blocks.append(self._heading_block(stripped[2:], level=1))
            elif stripped.startswith("- ") or stripped.startswith("* "):
                blocks.append(self._bullet_block(stripped[2:]))
            elif stripped.startswith("---"):
                blocks.append({"object": "block", "type": "divider", "divider": {}})
            else:
                blocks.append(self._paragraph_block(stripped))

        return blocks

    def _heading_block(self, text: str, level: int = 2) -> Dict[str, Any]:
        block_type = f"heading_{level}"
        return {
            "object": "block",
            "type": block_type,
            block_type: {"rich_text": [{"type": "text", "text": {"content": text}}]},
        }

    def _bullet_block(self, text: str) -> Dict[str, Any]:
        return {
            "object": "block",
            "type": "bulleted_list_item",
            "bulleted_list_item": {
                "rich_text": [{"type": "text", "text": {"content": text}}]
            },
        }

    def _paragraph_block(self, text: str) -> Dict[str, Any]:
        return {
            "object": "block",
            "type": "paragraph",
            "paragraph": {
                "rich_text": [{"type": "text", "text": {"content": text}}]
            },
        }

    def _build_page_payload(
        self,
        title: str,
        parent_id: str,
        blocks: List[Dict[str, Any]],
        is_database: bool = False,
    ) -> Dict[str, Any]:
        """Construit le payload de création de page Notion."""
        if is_database:
            parent = {"database_id": parent_id}
            # Pour une DB, le titre est une propriété "Name"
            properties = {
                "Name": {
                    "title": [{"type": "text", "text": {"content": title}}]
                }
            }
        else:
            parent = {"page_id": parent_id}
            properties = {
                "title": [{"type": "text", "text": {"content": title}}]
            }

        return {
            "parent": parent,
            "properties": properties,
            "children": blocks,
        }

    def _extract_title(self, item: Dict[str, Any]) -> str:
        """Extrait le titre d'un objet Notion (page ou DB) — gère tous les formats API."""
        props = item.get("properties", {})

        # Format DB item : propriété "Name" ou "Title" de type "title"
        for key in ["Name", "title", "Title"]:
            prop = props.get(key, {})
            # Format objet complet : {"type": "title", "title": [...]}
            if isinstance(prop, dict) and prop.get("type") == "title":
                texts = prop.get("title", [])
                if texts:
                    return texts[0].get("plain_text", "Sans titre")
            # Format liste directe : [{"plain_text": "..."}]
            if isinstance(prop, list) and prop:
                return prop[0].get("plain_text", "Sans titre")

        return "Sans titre"


