  border-collapse: separate;
  border-spacing: 0 3px;
}
.stbl th {
  font-size: 9px;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--t3);
  padding: 3px 8px;
  text-align: left;
}
.srow {
  background: rgba(255, 255, 255, 0.025);
  border-radius: 6px;
  transition: background 0.15s;
}
.srow:hover {
  background: rgba(255, 255, 255, 0.05);
}
.srow td {
  padding: 8px;
  font-size: 12px;
  vertical-align: middle;
}

/* PILLS & TAGS */
.pill {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 2px 8px;
  border-radius: 20px;
  font-size: 10px;
  font-weight: 700;
  font-family: var(--mono);
}
.pill.u {
  background: rgba(16, 185, 129, 0.12);
  border: 1px solid rgba(16, 185, 129, 0.3);
  color: var(--green);
}
.pill.d {
  background: rgba(239, 68, 68, 0.12);
  border: 1px solid rgba(239, 68, 68, 0.3);
  color: var(--red);
}
.pill.w {
  background: rgba(234, 179, 8, 0.12);
  border: 1px solid rgba(234, 179, 8, 0.3);
  color: var(--yellow);
}
.pdot {
  width: 5px;
  height: 5px;
  border-radius: 50%;
  background: currentColor;
  display: inline-block;
}
.ptag {
  font-family: var(--mono);
  font-size: 10px;
  color: var(--t3);
  background: rgba(255, 255, 255, 0.05);
  padding: 2px 6px;
  border-radius: 4px;
}
.plat {
  font-family: var(--mono);
  font-size: 11px;
  color: var(--t2);
}
.tag {
  display: inline-block;
  font-size: 9px;
  font-weight: 700;
  padding: 2px 6px;
  border-radius: 3px;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  font-family: var(--mono);
}
.tc {
  background: rgba(0, 212, 255, 0.1);
  color: var(--cyan);
  border: 1px solid rgba(0, 212, 255, 0.2);
}
.tp {
  background: rgba(139, 92, 246, 0.12);
  color: #a78bfa;
  border: 1px solid rgba(139, 92, 246, 0.25);
}
.tg {
  background: rgba(16, 185, 129, 0.12);
  color: var(--green);
  border: 1px solid rgba(16, 185, 129, 0.25);
}
.to {
  background: rgba(249, 115, 22, 0.12);
  color: var(--orange);
  border: 1px solid rgba(249, 115, 22, 0.25);
}
.tr {
  background: rgba(239, 68, 68, 0.12);
  color: var(--red);
  border: 1px solid rgba(239, 68, 68, 0.25);
}

/* LOGS */
.sbox {
  background: rgba(1, 2, 6, 0.85);
  border: 1px solid var(--border);
  border-radius: 8px;
  font-family: var(--mono);
  font-size: 11px;
  line-height: 1.75;
  padding: 10px 12px;
  overflow-y: auto;
  max-height: 220px;
}
.ll {
  display: flex;
  gap: 7px;
  line-height: 1.5;
}
.ts {
  color: var(--t3);
  flex-shrink: 0;
  font-size: 10px;
}
.lt {
  color: var(--t2);
}
.lt.s {
  color: var(--green);
}
.lt.e {
  color: var(--red);
}
.lt.w {
  color: var(--yellow);
}
.lt.i {
  color: var(--cyan);
}
.lt.x {
  color: #a78bfa;
}

/* AGENTS */
.acard {
  background: rgba(12, 18, 32, 0.6);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 16px;
  padding: 16px 12px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  cursor: default;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  position: relative;
  text-align: center;
  backdrop-filter: blur(10px);
  overflow: hidden;
}
.acard::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 2px;
  background: linear-gradient(90deg, transparent, var(--cyan), transparent);
  opacity: 0;
  transition: opacity 0.3s;
}
.acard:hover {
  border-color: rgba(0, 212, 255, 0.4);
  background: rgba(0, 212, 255, 0.05);
  transform: translateY(-4px);
  box-shadow: 0 8px 30px rgba(0, 212, 255, 0.15);
}
.acard:hover::before {
  opacity: 1;
}
.adot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--green);
  box-shadow: 0 0 10px var(--green);
  animation: pg 2s ease-in-out infinite;
  position: absolute;
  top: 10px;
  right: 10px;
}
.ae {
  font-size: 28px;
  line-height: 1;
  filter: drop-shadow(0 2px 4px rgba(0, 0, 0, 0.5));
}
.an {
  font-size: 13px;
  font-weight: 700;
  color: var(--t1);
  letter-spacing: 0.05em;
}
.agent-group-title {
  grid-column: 1 / -1;
  font-size: 11px;
  font-family: var(--mono);
  font-weight: 700;
  color: var(--t3);
  text-transform: uppercase;
  letter-spacing: 0.15em;
  padding-bottom: 8px;
  margin-top: 10px;
  border-bottom: 1px dashed var(--border);
}

/* FORMS */
.dta {
  background: rgba(0, 0, 0, 0.5);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 8px;
  padding: 10px 12px;
  color: var(--t1);
  font-size: 13px;
  outline: none;
  resize: none;
  width: 100%;
  font-family: var(--sans);
  transition: border-color 0.2s;
}
.dta:focus {
  border-color: rgba(0, 212, 255, 0.4);
}
.ds {
  background: rgba(0, 0, 0, 0.4);
  border: 1px solid var(--border);
  color: var(--t2);
  padding: 7px 10px;
  border-radius: 6px;
  font-size: 11px;
  font-family: var(--sans);
  outline: none;
}
.btn {
  padding: 6px 16px;
  border-radius: 99px;
  font-size: 12px;
  font-weight: 600;
  border: none;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  gap: 5px;
  font-family: var(--sans);
  transition: all 0.2s;
}
.bp {
  background: var(--cyan);
  color: #000;
}
.bp:hover {
  box-shadow: 0 4px 18px rgba(0, 212, 255, 0.35);
  filter: brightness(1.1);
}
.bg {
  background: rgba(255, 255, 255, 0.07);
  color: var(--t2);
  border: 1px solid var(--border);
}
.bg:hover {
  background: rgba(255, 255, 255, 0.12);
  color: var(--t1);
}
.bc {
  background: rgba(0, 212, 255, 0.12);
  color: var(--cyan);
  border: 1px solid rgba(0, 212, 255, 0.25);
  text-decoration: none;
}
.bc:hover {
  background: rgba(0, 212, 255, 0.2);
}

/* SPARKLINES */
.spkw {
  display: flex;
  align-items: flex-end;
  gap: 2px;
  height: 28px;
  margin-top: 8px;
}
.spk {
  flex: 1;
  border-radius: 2px 2px 0 0;
  min-width: 3px;
  transition: height 0.4s ease;
}

/* INFRA METRIC CARDS */
.metric-big {
  text-align: center;
  padding: 16px 16px 8px;
}
.metric-val-big {
  font-size: 38px;
  font-weight: 800;
  font-family: var(--mono);
  line-height: 1;
  transition: all 0.4s;
}
.metric-lbl-big {
  font-size: 9px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--t3);
  margin-top: 6px;
}
.metric-bar-big {
  margin: 12px auto 0;
  max-width: 100%;
  height: 4px;
  background: rgba(255, 255, 255, 0.06);
  border-radius: 2px;
  overflow: hidden;
}
.metric-bar-fill {
  height: 100%;
  border-radius: 2px;
  transition: width 0.8s ease;
}

/* N8N VIEW */
.n8n-hero {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 14px 18px;
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}
.n8n-title {
  font-size: 14px;
  font-weight: 700;
  display: flex;
  align-items: center;
  gap: 8px;
}
.n8n-actions {
  margin-left: auto;
  display: flex;
  gap: 8px;
  align-items: center;
}
.n8n-stat-row {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}
.n8n-stat {
  text-align: center;
  padding: 14px 10px;
  border-right: 1px solid var(--border);
}
.n8n-stat:last-child {
  border-right: none;
}
.n8n-stat-val {
  font-size: 24px;
  font-weight: 700;
  font-family: var(--mono);
}
.n8n-stat-lbl {
  font-size: 9px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: var(--t3);
  margin-top: 3px;
}
.wflow-list {
  overflow-y: auto;
  flex: 1;
}
.wflow-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px 16px;
  border-bottom: 1px solid var(--border);
  transition: background 0.15s;
  cursor: default;
}
.wflow-item:hover {
  background: rgba(255, 255, 255, 0.03);
}
.wflow-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
}
.wflow-dot.on {
  background: var(--green);
  box-shadow: 0 0 8px var(--green);
  animation: pg 2s infinite;
}
.wflow-dot.off {
  background: var(--t3);
}
.wflow-name {
  font-size: 13px;
  font-weight: 500;
}
.wflow-meta {
  font-size: 10px;
  color: var(--t3);
  margin-top: 2px;
  font-family: var(--mono);
}
.wflow-empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 120px;
  color: var(--t3);
  font-size: 12px;
  gap: 8px;
}
.exec-item {
  padding: 10px 14px;
  border-bottom: 1px solid var(--border);
  font-size: 11px;
  font-family: var(--mono);
}
.exec-item:hover {
  background: rgba(255, 255, 255, 0.03);
}
.exec-status {
  font-size: 9px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  margin-top: 2px;
}
.auth-notice {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 40px;
  gap: 12px;
  color: var(--t2);
  text-align: center;
}
.auth-notice h3 {
  color: var(--t1);
  margin-bottom: 6px;
}
.auth-notice code {
  font-family: var(--mono);
  background: rgba(0, 212, 255, 0.1);
  color: var(--cyan);
  padding: 4px 10px;
  border-radius: 4px;
  font-size: 12px;
}


/* CHAT BUBBLES */
.chat-bubble {
  max-width: 85%;
  padding: 8px 14px;
  border-radius: 18px;
  font-size: 13px;
  line-height: 1.5;
  margin-bottom: 4px;
  backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.08);
  word-wrap: break-word;
  animation: fadeIn 0.3s ease;
}
.chat-bubble.bg {
  background: rgba(10, 132, 255, 0.2);
  border-color: rgba(10, 132, 255, 0.3);
  color: #fff;
  align-self: flex-end;
  border-bottom-right-radius: 4px;
}
.chat-bubble.bp {
  background: rgba(255, 255, 255, 0.05);
  color: var(--t1);
  align-self: flex-start;
  border-bottom-left-radius: 4px;
}
@keyframes fadeIn {
  from { opacity: 0; transform: translateY(5px); }
  to { opacity: 1; transform: translateY(0); }
}

","index.html":"<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8"/>
<meta name="viewport" content="width=device-width,initial-scale=1"/>
<meta name="description" content="TwisterLab Mission Control — AI Agent Orchestration Platform"/>
<title>TwisterLab · Mission Control</title>
<link rel="preconnect" href="https://fonts.googleapis.com"/>
<link href="https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700;800&family=JetBrains+Mono:wght@400;500;700&display=swap" rel="stylesheet"/>
<link rel="stylesheet" href="/index.css?v=6" />
</head>
<body>
<div id="shell">

  <!-- TOP BAR -->
  <header id="top">
    <div class="logo">
      <div class="logo-icon">⚡</div>
      <span class="logo-name">TWISTERLAB</span>
      <span class="logo-ver">v3.7.0</span>
    </div>
    <div style="width:1px;height:18px;background:var(--border);margin:0 4px"></div>
    <div class="top-stat">
      <span class="dot" id="gdot"></span>
      <span id="gstat" style="color:var(--cyan)">MISSION CONTROL</span>
    </div>
    <div class="sep"></div>
    <div style="display:flex;align-items:center;gap:14px">
      <span style="font-size:10px;color:var(--t3);font-family:var(--mono)">CLUSTER: 192.168.0.30</span>
      <div class="top-clock" id="clk">--:--:--</div>
    </div>
  </header>

  <!-- SIDEBAR -->
  <nav id="side">
    <span class="nsec">Operations</span>
    <button class="ni on" data-v="ov"><span class="ic">🧭</span><span>Overview</span></button>
    <button class="ni" data-v="ag"><span class="ic">🤖</span><span>Agents</span><span class="nb g" id="agentBadge">11</span></button>
    <button class="ni" data-v="ma"><span class="ic">🧠</span><span>Maestro</span></button>
    <button class="ni" data-v="inf"><span class="ic">☸</span><span>Infrastructure</span></button>
    <span class="nsec">Workspace</span>
    <button class="ni" data-v="n8"><span class="ic">⚡</span><span>n8n Workflows</span><span class="nb o">LIVE</span></button>
    <button class="ni" data-v="no"><span class="ic">📓</span><span>Knowledge Base</span><span class="nb c">NOTION</span></button>
    <div class="sfooter"><b id="aonline">--</b> agents online</div>
  </nav>

  <!-- MAIN -->
  <main id="main">

    <!-- ====== OVERVIEW ====== -->
    <div class="view on" id="view-ov">
      <div class="krow">
        <div class="kcard">
          <div class="klbl">CPU Usage</div>
          <div class="kval c" id="kpu">--%</div>
          <div class="ksub" id="kpu-sub">…</div>
          <div class="kbw"><div class="kb c" id="bpu"></div></div>
          <div class="spkw" id="spcpu"></div>
        </div>
        <div class="kcard">
          <div class="klbl">RAM Usage</div>
          <div class="kval p" id="kram">--%</div>
          <div class="ksub" id="kram-sub">…</div>
          <div class="kbw"><div class="kb p" id="bram"></div></div>
          <div class="spkw" id="spram"></div>
        </div>
        <div class="kcard">
          <div class="klbl">Services Up</div>
          <div class="kval g" id="kact">--</div>
          <div class="ksub" id="kact-sub">Scanning…</div>
          <div class="kbw"><div class="kb g" id="bact"></div></div>
        </div>
        <div class="kcard">
          <div class="klbl">API Latency</div>
          <div class="kval o" id="klat">--ms</div>
          <div class="ksub" id="klat-sub">Measuring…</div>
          <div class="kbw"><div class="kb o" id="blat" style="width:15%"></div></div>
        </div>
      </div>
      <div class="g2">
        <div class="panel">
          <div class="ph"><span class="pi">▦</span><span class="pt">Service Core</span><span class="pbadge" id="svc-badge"></span></div>
          <div class="pb">
            <table class="stbl">
              <thead><tr><th>Service</th><th>Status</th></tr></thead>
              <tbody id="mtbody"><tr><td colspan="2" style="color:var(--t3);text-align:center;padding:16px;font-size:11px">Scanning…</td></tr></tbody>
            </table>
          </div>
        </div>
        <div class="panel">
          <div class="ph"><span class="pi">◉</span><span class="pt">Live Events</span></div>
          <div class="pb"><div class="sbox" id="slog"></div></div>
        </div>
      </div>
    </div>

    <!-- ====== AGENTS ====== -->
    <div class="view" id="view-ag">
      <div class="panel">
        <div class="ph"><span class="pi">🤖</span><span class="pt">Agent Registry</span><span class="pbadge" id="ag-count"></span></div>
        <div class="pb"><div class="g-auto" id="agrid"></div></div>
      </div>
    </div>

    <!-- ====== MAESTRO ====== -->
    <div class="view" id="view-ma" style="flex-direction:row;gap:14px">
      <div class="panel" style="width:190px;flex-shrink:0">
        <div class="ph"><span class="pi">📜</span><span class="pt">Archive</span></div>
        <div class="pb" id="mhist" style="font-family:var(--mono);font-size:10px;display:flex;flex-direction:column;gap:3px"></div>
      </div>
      <div style="flex:1.2;display:flex;flex-direction:column;gap:14px">
        <div class="panel">
          <div class="ph"><span class="pi">🧠</span><span class="pt">Mission Dispatch</span><span class="pbadge" id="mbadge">IDLE</span></div>
          <div class="pb">
            <textarea class="dta" id="minput" rows="3" placeholder="Describe your mission goal…"></textarea>
            <div style="display:flex;gap:8px;margin-top:8px;align-items:center">
              <select class="ds" id="mmode"><option value="orchestrate">Live Dispatch</option><option value="dry_run">Dry Run</option></select>
              <button class="btn bp" id="dbtn" onclick="dispatch()">⚡ Send</button>
            </div>
          </div>
        </div>
        <div class="panel" style="flex:1;min-height:160px">
          <div class="ph"><span class="pi">📋</span><span class="pt">Mission Logs</span></div>
          <div class="pb"><div class="sbox" id="mout" style="max-height:220px"></div></div>
        </div>
      </div>
      <div class="panel" style="flex:1">
        <div class="ph"><span class="pi">💬</span><span class="pt">Cortex AI</span>
          <select id="cortex-model" class="ds" style="margin-left:8px;padding:2px 6px;font-size:9px;max-width:120px" title="Modèle LLM"></select>
          <button class="btn bg" onclick="doClearChat()" style="margin-left:auto;padding:2px 8px;font-size:10px;border-radius:4px;opacity:0.8">🗑 Reset</button>
        </div>
        <div class="pb" style="display:flex;flex-direction:column;height:100%;gap:10px">
          <div id="cchat" style="flex:1;overflow-y:auto;display:flex;flex-direction:column;gap:10px;min-height:80px"></div>
          <div style="display:flex;gap:8px;border-top:1px solid var(--border);padding-top:10px;flex-shrink:0">
            <input type="text" id="chat-in" placeholder="Ask Cortex anything…" style="flex:1;background:rgba(0,0,0,.35);border:1px solid var(--border);border-radius:6px;color:#fff;padding:8px 12px;font-size:12px;font-family:var(--sans);outline:none" onkeydown="if(event.key==='Enter')sendChat()"/>
            <button class="btn bp" onclick="sendChat()">Send</button>
          </div>
        </div>
      </div>
    </div>

    <!-- ====== INFRASTRUCTURE ====== -->
    <div class="view" id="view-inf">
      <div class="g3">
        <div class="panel">
          <div class="ph"><span class="pi">🖥️</span><span class="pt">CPU</span></div>
          <div class="pb">
            <div class="metric-big">
              <div class="metric-val-big c" id="mcpu">--%</div>
              <div class="metric-lbl-big">Processor Load</div>
              <div class="metric-bar-big"><div class="metric-bar-fill" id="bcpu-bar" style="background:linear-gradient(90deg,var(--cyan),var(--purple))"></div></div>
            </div>
            <div class="spkw" id="spcpu2" style="height:38px;padding:0 10px"></div>
          </div>
        </div>
        <div class="panel">
          <div class="ph"><span class="pi">💾</span><span class="pt">Memory</span></div>
          <div class="pb">
            <div class="metric-big">
              <div class="metric-val-big p" id="mram">--%</div>
              <div class="metric-lbl-big" id="mram-sub">RAM</div>
              <div class="metric-bar-big"><div class="metric-bar-fill" id="bram-bar" style="background:linear-gradient(90deg,var(--purple),#60a5fa)"></div></div>
            </div>
            <div class="spkw" id="spram2" style="height:38px;padding:0 10px"></div>
          </div>
        </div>
        <div class="panel">
          <div class="ph"><span class="pi">💿</span><span class="pt">Disk</span></div>
          <div class="pb">
            <div class="metric-big">
              <div class="metric-val-big o" id="mdsk">--%</div>
              <div class="metric-lbl-big" id="mdsk-sub">Storage</div>
              <div class="metric-bar-big"><div class="metric-bar-fill" id="bdsk-bar" style="background:linear-gradient(90deg,var(--orange),var(--yellow))"></div></div>
            </div>
            <div class="spkw" id="spdsk2" style="height:38px;padding:0 10px"></div>
          </div>
        </div>
      </div>
      <div class="panel">
        <div class="ph"><span class="pi">⚡</span><span class="pt">Service Health</span><span class="pbadge" id="svc-count-badge">Scanning…</span></div>
        <div class="pb">
          <table class="stbl">
            <thead><tr><th></th><th>Service</th><th>Port</th><th>Status</th></tr></thead>
            <tbody id="svctbody"><tr><td colspan="4" style="color:var(--t3);text-align:center;padding:20px;font-size:11px">Scanning services…</td></tr></tbody>
          </table>
        </div>
      </div>
    </div>


    <!-- ====== N8N WORKFLOWS ====== -->
    <div class="fullh" id="view-n8">
      <div class="panel" style="flex:1;overflow:hidden">
