<script>

// ===================== CLOCK =====================
setInterval(()=>{document.getElementById('clk').textContent=new Date().toLocaleTimeString()},1000);

// ===================== NAV =====================
document.querySelectorAll('.ni').forEach(b=>{
  b.onclick=()=>{
    document.querySelectorAll('.ni').forEach(x=>x.classList.remove('on'));b.classList.add('on');
    document.querySelectorAll('.view,.fullh').forEach(v=>v.classList.remove('on'));
    const t=document.getElementById('view-'+b.dataset.v);if(t)t.classList.add('on');
    if(b.dataset.v==='n8')fetchN8nWorkflows();
    if(b.dataset.v==='inf')fetchServices();
    if(b.dataset.v==='no')fetchNotionPages();
  };
});

// ===================== HELPERS =====================
const $=id=>document.getElementById(id);
function setEl(id,txt){const e=$(id);if(e)e.textContent=txt;}
function setW(id,pct){const e=$(id);if(e)e.style.width=Math.min(100,Math.max(0,pct))+'%';}

// ===================== LOGGING =====================
const L=$('slog');
function log(m,t='i'){
  if(!L)return;
  const d=document.createElement('div');d.className='ll';
  d.innerHTML=`<span class="ts">${new Date().toLocaleTimeString()}</span><span class="lt ${t}">${m}</span>`;
  L.appendChild(d);if(L.children.length>60)L.removeChild(L.firstChild);L.scrollTop=L.scrollHeight;
}

// ===================== SPARKLINES =====================
const sparkH={cpu:[],ram:[],disk:[]};const MAX_SP=22;
function pushSp(arr,v){arr.push(v);if(arr.length>MAX_SP)arr.shift();}
function renderSp(id,data,color){
  const c=$(id);if(!c||!data.length)return;
  const mx=Math.max(...data,1);
  c.innerHTML=data.map(v=>{
    const h=Math.max(2,Math.round((v/mx)*36));
    return `<div class="spk" style="height:${h}px;background:${color};opacity:${.3+(v/mx)*.7}"></div>`;
  }).join('');
}

// ===================== TELEMETRY =====================
async function fetchTele(){
  const t0=performance.now();
  try{
    const r=await fetch('/api/dashboard/telemetry',{method:'POST',headers:{'Content-Type':'application/json'},body:'{}'});
    const rtt=Math.round(performance.now()-t0);
    const raw=await r.json();let d={};
    if(raw.content?.[0]?.text)d=JSON.parse(raw.content[0].text);
    const sys=d.services?.system||{};
    const agents=d.agents||[];

    // Metrics
    const cpu=sys.cpu_percent||0;
    const mem=sys.memory_percent||0;
    const disk=sys.disk_percent||0;
    const memUsed=sys.memory_used_gb||0;
    const memTotal=sys.memory_total_gb||0;
    const diskUsed=sys.disk_used_gb||0;
    const diskTotal=sys.disk_total_gb||0;

    // KPI Update
    setEl('kpu',Math.round(cpu)+'%');setEl('kpu-sub','Node load');setW('bpu',cpu);
    setEl('kram',Math.round(mem)+'%');setEl('kram-sub',memTotal?`${memUsed}/${memTotal} GB`:'');setW('bram',mem);
    setEl('klat',rtt+'ms');setEl('klat-sub','Round-trip');
    const latPct=Math.min(100,rtt/5);setW('blat',latPct);

    // Agents
    const cnt=agents.length||11;
    setEl('aonline',cnt);setEl('agentBadge',cnt);setEl('ag-count',cnt+' agents');

    // Sparklines
    pushSp(sparkH.cpu,cpu);pushSp(sparkH.ram,mem);pushSp(sparkH.disk,disk);
    renderSp('spcpu',sparkH.cpu,'var(--cyan)');
    renderSp('spram',sparkH.ram,'#a78bfa');

    // Infra view
    setEl('mcpu',Math.round(cpu)+'%');setEl('mram',Math.round(mem)+'%');setEl('mdsk',Math.round(disk)+'%');
    if(memTotal>0)setEl('mram-sub',`${memUsed} / ${memTotal} GB`);
    if(diskTotal>0)setEl('mdsk-sub',`${diskUsed} / ${diskTotal} GB`);
    const bcpu=$('bcpu-bar');if(bcpu)bcpu.style.width=cpu+'%';
    const bram=$('bram-bar');if(bram)bram.style.width=mem+'%';
    const bdsk=$('bdsk-bar');if(bdsk)bdsk.style.width=disk+'%';
    renderSp('spcpu2',sparkH.cpu,'var(--cyan)');
    renderSp('spram2',sparkH.ram,'#a78bfa');
    renderSp('spdsk2',sparkH.disk,'var(--orange)');

    log(`CPU ${Math.round(cpu)}% · RAM ${Math.round(mem)}% · RTT ${rtt}ms`,'i');
  }catch(e){log('Telemetry error: '+e.message,'e');}
}
setInterval(fetchTele,8000);fetchTele();

// ===================== SERVICES =====================
async function fetchServices(){
  try{
    const r=await fetch('/api/dashboard/services');
    const d=await r.json();
    const svcs=d.services||[];
    const up=svcs.filter(s=>s.status==='up').length;
    setEl('kact',`${up}/${svcs.length}`);
    setEl('kact-sub',`${up} healthy`);
    setW('bact',(up/Math.max(svcs.length,1))*100);
    setEl('svc-badge',`${up}/${svcs.length} UP`);
    setEl('svc-count-badge',`${up}/${svcs.length} UP`);
    const mkPill=(s)=>s==='up'?'<span class="pill u"><span class="pdot"></span>UP</span>':s==='degraded'?'<span class="pill w"><span class="pdot"></span>DEGRADED</span>':'<span class="pill d"><span class="pdot"></span>DOWN</span>';
    const emojis={up:'🟢',degraded:'🟡',down:'🔴'};
    const tbl=$('svctbody');
    if(tbl)tbl.innerHTML=svcs.map(s=>`<tr class="srow"><td style="font-size:14px;padding-left:10px">${emojis[s.status]||'⚪'}</td><td class="plat" style="color:var(--t1)">${s.name}</td><td><span class="ptag">:${s.port}</span></td><td>${mkPill(s.status)}</td></tr>`).join('');
    const ov=$('mtbody');
    if(ov)ov.innerHTML=svcs.map(s=>`<tr class="srow"><td style="color:var(--t2)">${s.name}</td><td>${mkPill(s.status)}</td></tr>`).join('');
    log(`Services: ${up}/${svcs.length} UP`,'s');
  }catch(e){console.warn('Services probe failed',e);}
}
setInterval(fetchServices,20000);fetchServices();

// ===================== N8N WORKFLOWS =====================
async function fetchN8nWorkflows(){
  const wfEl=$('n8n-workflows');
  const exEl=$('n8n-executions');
  const statEl=$('n8nEngineStatus');
  const dot=$('n8dot');
  try{
    const r=await fetch('/api/dashboard/n8n');
    const d=await r.json();
    if(d.status==='offline'){
      if(dot)dot.className='dot err';
      if(statEl)statEl.textContent='ENGINE OFFLINE';
      if(wfEl)wfEl.innerHTML='<div class="wflow-empty"><span style="font-size:28px">🔴</span>n8n engine is unreachable</div>';
      return;
    }
    if(dot)dot.className='dot';
    if(statEl)statEl.textContent='ENGINE ONLINE';
    setEl('n8n-total',d.workflows.length);
    setEl('n8n-active',d.workflows.filter(w=>w.active).length);
    setEl('n8n-execs',d.executions.length);
    if(d.auth_required&&!d.api_key_configured){
      if(wfEl)wfEl.innerHTML=`
        <div class="auth-notice">
          <span style="font-size:36px">🔑</span>
          <h3>API Key Required</h3>
          <p style="font-size:12px;color:var(--t3);max-width:320px">n8n requires authentication to list workflows. Set the <code>N8N_API_KEY</code> environment variable in your Kubernetes deployment.</p>
          <div style="font-family:var(--mono);font-size:11px;background:rgba(0,0,0,.4);border:1px solid var(--border);border-radius:8px;padding:12px 16px;margin-top:8px;color:var(--cyan);text-align:left">
            kubectl set env deployment/twisterlab-api<br>
            &nbsp;&nbsp;N8N_API_KEY=your-n8n-key -n twisterlab
          </div>
          <a href="http://192.168.0.30:5678" target="_blank" class="btn bc" style="margin-top:8px">↗ Open n8n to get API Key</a>
        </div>`;
      if(exEl)exEl.innerHTML='<div class="wflow-empty">Auth required</div>';
      return;
    }
    // Render workflows
    if(wfEl){
      if(d.workflows.length===0){
        wfEl.innerHTML='<div class="wflow-empty"><span style="font-size:28px">📭</span>No workflows found<br><small style="font-size:10px">Create your first workflow in n8n</small></div>';
      }else{
        wfEl.innerHTML=d.workflows.map(w=>`
          <div class="wflow-item">
            <div class="wflow-dot ${w.active?'on':'off'}"></div>
            <div style="flex:1;min-width:0">
              <div class="wflow-name" style="white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${w.name||'Unnamed Workflow'}</div>
              <div class="wflow-meta">${(w.nodes||[]).length} nodes · ${w.active?'Active':'Inactive'} · ID: ${w.id}</div>
            </div>
            <span class="tag ${w.active?'tg':'tr'}">${w.active?'LIVE':'OFF'}</span>
          </div>`).join('');
      }
    }
    // Render executions
    if(exEl){
      if(d.executions.length===0){
        exEl.innerHTML='<div class="wflow-empty"><span>📭</span>No executions</div>';
      }else{
        const statusColor={success:'var(--green)',error:'var(--red)',running:'var(--cyan)',waiting:'var(--yellow)'};
        exEl.innerHTML=d.executions.map(e=>{
          const ts=e.startedAt||e.stoppedAt||'';
          const time=ts?new Date(ts).toLocaleTimeString():'';
          const wfName=e.workflowData?.name||e.workflowName||'—';
          const st=e.finished===false?'running':e.status||'unknown';
          const col=statusColor[st]||'var(--t3)';
          return `<div class="exec-item"><div style="color:var(--t1);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${wfName}</div><div class="exec-status" style="color:${col}">${st.toUpperCase()}${time?' · '+time:''}</div></div>`;
        }).join('');
      }
    }
  }catch(e){
    if(dot)dot.className='dot err';
    if(statEl)statEl.textContent='ENGINE ERROR';
    console.error('n8n fetch error',e);
  }
}

// ===================== MAESTRO DISPATCH =====================
const mout=$('mout');
function mlog(m,t='i'){const d=document.createElement('div');d.className='ll';d.innerHTML=`<span class="ts">${new Date().toLocaleTimeString()}</span> <span class="lt ${t}">${m}</span>`;mout.appendChild(d);mout.scrollTop=mout.scrollHeight;}

async function dispatch(){
  const task=$('minput').value.trim();if(!task)return;
  const btn=$('dbtn'),badge=$('mbadge');
  btn.disabled=true;badge.textContent='RUNNING';
  mlog('▶ Mission: '+task,'i');
  try{
    const r=await fetch('/api/tools/maestro_orchestrate',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({arguments:{task}})});
    const raw=await r.json();
    let res={};
    if(raw.content?.[0]?.text){try{res=JSON.parse(raw.content[0].text);}catch(e){res={result:raw.content[0].text};}}
    else if(!raw.isError){res={result:JSON.stringify(raw)};}
    mlog('✓ '+(res.result||res.synthesis||res.message||'Mission complete'),'s');
    badge.textContent='DONE';
    const mid='M-'+Math.random().toString(36).substring(2,9).toUpperCase();
    fetch('/api/dashboard/archive',{
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({mission_id:mid,data:{task,result:res,timestamp:new Date().toISOString()}})
    }).then(()=>fetchHistory()).catch(e=>console.warn('Archive failed:',e));
    askCortex(`Résume en 2 phrases ce résultat de mission: ${JSON.stringify(res)}`);
  }catch(e){mlog('✗ '+e.message,'e');badge.textContent='ERROR';}
  finally{btn.disabled=false;}
}

// ===================== HISTORY =====================
async function fetchHistory(){
  try{
    const r=await fetch('/api/dashboard/history',{method:'POST',headers:{'Content-Type':'application/json'},body:'{}'});
    const raw=await r.json();
    let parsed={};
    if(raw.content?.[0]?.text){try{parsed=JSON.parse(raw.content[0].text);}catch(e){}}
    else if(raw.status==='success'||raw.data){parsed=raw;}
    const hl=$('mhist');if(!hl)return;
    const items=parsed.data||[];
    if(items.length===0){
      hl.innerHTML='<div style="color:var(--t3);font-size:10px;padding:8px;text-align:center">Aucune mission archivée</div>';
      return;
    }
    hl.innerHTML=items.map(m=>{
      const label=(m.task||m.id||'Mission').slice(0,24);
      const ts=m.timestamp?new Date(m.timestamp).toLocaleString('fr',{hour:'2-digit',minute:'2-digit',day:'2-digit',month:'2-digit'}):'--';
      return `<div style="padding:6px 4px;border-bottom:1px solid var(--border);cursor:pointer;transition:background .15s" onmouseover="this.style.background='rgba(0,212,255,0.05)'" onmouseout="this.style.background=''">
        <div style="color:var(--cyan);font-size:10px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${label}</div>
        <div style="color:var(--t3);font-size:9px;margin-top:1px;font-family:var(--mono)">${ts}</div>
      </div>`;
    }).join('');
  }catch(e){
    console.warn('History fetch failed',e);
    $('mhist').innerHTML='<div style="color:var(--t3);font-size:10px;padding:8px">Historique indisponible</div>';
  }
}

// ===================== CORTEX CHAT =====================
function appendBubble(type,html,save=true){
  const b=document.createElement('div');b.className=`chat-bubble ${type==='human'?'bg':'bp'}`;
  b.style.alignSelf=type==='human'?'flex-end':'flex-start';b.dataset.type=type;b.innerHTML=html;
  const c=$('cchat');c.appendChild(b);c.scrollTop=c.scrollHeight;
  if(save)saveChat();
}
function sendChat(){const i=$('chat-in'),t=i.value.trim();if(!t)return;appendBubble('human',t);i.value='';askCortex(t);}
function doClearChat(){localStorage.removeItem('twister_chat_v4');const c=$('cchat');if(c)c.innerHTML='';log('Chat history cleared','i');}
function saveChat(){const m=Array.from(document.querySelectorAll('.chat-bubble')).map(b=>({type:b.dataset.type,html:b.innerHTML})).slice(-50);localStorage.setItem('twister_chat_v4',JSON.stringify(m));}
function loadChat(){try{const l=localStorage.getItem('twister_chat_v4');if(l){JSON.parse(l).forEach(m=>appendBubble(m.type,m.html,false));const c=$('cchat');if(c)setTimeout(()=>c.scrollTop=c.scrollHeight,100);}}catch(e){}}
async function loadModels(){
  try{
    const r=await fetch('/api/dashboard/cortex/models');
    const d=await r.json();
    const sel=$('cortex-model');if(!sel)return;
    const models=d.models||['llama3.2:1b'];
    sel.innerHTML=models.map(m=>`<option value="${m}" ${m===d.default?'selected':''}>${m}</option>`).join('');
  }catch(e){ const sel=$('cortex-model');if(sel)sel.innerHTML='<option value="llama3.2:1b">llama3.2:1b</option>'; }
}

async function askCortex(txt){
  try{
    const sel=$('cortex-model');
    const model=sel?sel.value:null;
    const history = Array.from(document.querySelectorAll('.chat-bubble')).slice(-10).map(b => ({
      role: b.dataset.type,
      text: b.innerText
    }));
    const body={input:txt, history: history};
    if(model)body.model=model;
    const r=await fetch('/api/dashboard/cortex',{
      method:'POST',
      headers:{'Content-Type':'application/json;charset=utf-8'},
      body:JSON.stringify(body)
    });
    const raw=await r.json();
    let ans=raw.isError
      ? (raw.content?.[0]?.text||'❌ Erreur Cortex')
      : (raw.content?.[0]?.text||'⚠️ Réponse vide');
    appendBubble('ai',ans);
  }catch(e){appendBubble('ai','❌ Cortex inaccessible: '+e.message);}
}

// ===================== AGENTS (LIVE FROM API) =====================
const AGENT_TAGS={
  'maestro':'tp','monitoring':'tc','real-desktop-commander':'tc','browser':'tc',
  'real-classifier':'tg','real-resolver':'to','sentiment-analyzer':'tg',
  'code-review':'tc','cache':'tc','database':'tp','real-backup':'to',
  'real-sync':'tc','cortex-ia':'tp','n8n-navigator':'to','real-vba-expert':'tc',
  'real-translation':'tg','real-summarizer':'tg'
};
const AGENT_EMOJIS={
  'maestro':'🧠','monitoring':'📊','real-desktop-commander':'💻','browser':'🌍',
  'real-classifier':'🏷️','real-resolver':'🔧','sentiment-analyzer':'🎭',
  'code-review':'🔍','cache':'⚡','database':'🗄️','real-backup':'💾',
  'real-sync':'🔄','cortex-ia':'🔮','n8n-navigator':'⚡','real-vba-expert':'📋',
  'real-translation':'🌐','real-summarizer':'📝'
};
async function loadAgents(){
  try{
    const r=await fetch('/api/dashboard/agents');
    const d=await r.json();
    const agents=d.agents||[];
    const cnt=d.count||agents.length;
    setEl('aonline',cnt);
    setEl('agentBadge',cnt);
    setEl('ag-count',cnt+' agents online');
    // Render in agent grid
    const g=$('agrid');if(!g)return;
    const groups = {
      '🧠 Intelligence & Core': ['maestro', 'cortex-ia'],
      '🛠️ Tools & DevOps': ['n8n-navigator', 'monitoring', 'browser', 'database', 'cache', 'real-desktop-commander'],
      '📝 Data & Languages': ['real-classifier', 'sentiment-analyzer', 'real-summarizer', 'real-translation', 'code-review', 'real-vba-expert'],
      '🛡️ Support & Continuity': ['real-resolver', 'real-backup', 'real-sync']
    };
    let html = '';
    for(const [gName, identifiers] of Object.entries(groups)) {
      let gAgents = agents.filter(a => identifiers.includes(a.name));
      if (identifiers === groups['🛡️ Support & Continuity']) gAgents.push(...agents.filter(a => !Object.values(groups).flat().includes(a.name)));
      if(gAgents.length === 0) continue;
      html += `<div class="agent-group-title">${gName}</div>`;
      html += gAgents.map(a=>{
        const tc=AGENT_TAGS[a.name]||'tc';
        const em=AGENT_EMOJIS[a.name]||'🤖';
        const capCount=(a.capabilities||[]).length;
        const cname=a.class?a.class.replace('Agent','').replace('Real','').replace('Analyzer','').toLowerCase():'agent';
        return `<div class="acard">
          <div class="adot"></div>
          <div class="ae">${em}</div>
          <div class="an">${a.name}</div>
          <span class="tag ${tc}" style="font-size:9px">${cname}</span>
          ${capCount>0?`<div style="font-size:10px;color:var(--t2);font-family:var(--mono);margin-top:4px">${capCount} tools</div>`:''}
        </div>`;
      }).join('');
    }
    g.innerHTML = html;
    log(`Agents: ${cnt} online`,'s');
  }catch(e){
    console.warn('Agent load failed:',e);
    // Render static fallback
    const staticAgents=[
      {name:'maestro',em:'🧠',tc:'tp',tag:'orchestrator'},{name:'monitoring',em:'📊',tc:'tc',tag:'infra'},
